import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Pointer } from 'lucide-react';
import DialogueBox from '../../../DialogueBox';
import { useGame } from '../../../../context/GameContext';
import { GameState } from '../../../../types/game-state';

/**
 * 마켓 튜토리얼 전용 단계 타입
 * GameState의 tutorialStep 중 마켓 관련 단계만 추출
 */
export type SequenceStep = Extract<GameState['tutorialStep'], 
    'BROWSE_GOODS_GUIDE' | 
    'FURNACE_GUIDE' | 
    'OPEN_SHOPPING_CART' | 
    'CLOSE_SHOPPING_CART' | 
    'PAY_NOW' | 
    'GARRICK_AFTER_PURCHASE_DIALOG' | 
    'LEAVE_MARKET_GUIDE'
>;

interface StepConfig {
    targetId: string;
    label: string;
    direction: 'top' | 'bottom' | 'left' | 'right';
}

const SCENE_STEPS_CONFIG: Record<SequenceStep, StepConfig> = {
    BROWSE_GOODS_GUIDE: { targetId: 'BROWSE_GOODS_BUTTON', label: 'Browse Goods', direction: 'top' },
    FURNACE_GUIDE: { targetId: 'FURNACE_ITEM', label: 'Select the Furnace', direction: 'bottom' },
    OPEN_SHOPPING_CART: { targetId: 'CART_TOGGLE', label: 'Open the Cart', direction: 'left' },
    CLOSE_SHOPPING_CART: { targetId: 'CART_TOGGLE', label: 'Close the Cart', direction: 'right' },
    PAY_NOW: { targetId: 'PAY_NOW_BUTTON', label: 'Finalize Purchase', direction: 'bottom' },
    GARRICK_AFTER_PURCHASE_DIALOG: { targetId: 'GARRICK_TALK_BUTTON', label: 'Talk to Garrick', direction: 'top' },
    LEAVE_MARKET_GUIDE: { targetId: 'MARKET_BACK_BUTTON', label: 'Return to Forge', direction: 'bottom' },
};

const SCRIPTS: Record<SequenceStep, { speaker: string; text: string }> = {
    BROWSE_GOODS_GUIDE: { speaker: "Garrick", text: "Welcome back, smith! Open up my catalog and see what catches your eye." },
    FURNACE_GUIDE: { speaker: "Garrick", text: "There it is! Not as grand as your old one, but it'll bring the fire back." },
    OPEN_SHOPPING_CART: { speaker: "Garrick", text: "Going to settle the bill? Open your cart on the right." },
    CLOSE_SHOPPING_CART: { speaker: "Garrick", text: "Now close the list so we can talk business." },
    PAY_NOW: { speaker: "Garrick", text: "Hand over the coin, and the future is yours." },
    GARRICK_AFTER_PURCHASE_DIALOG: { speaker: "Lockhart", text: "I should say goodbye to Garrick before I leave." },
    LEAVE_MARKET_GUIDE: { speaker: "Garrick", text: "Safe travels, Lockhart. Don't let those embers go cold again." },
};

export const MarketTutorialOverlay = ({ step }: { step: SequenceStep }) => {
    const { actions } = useGame();
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];
    const script = SCRIPTS[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.querySelector(`[data-tutorial-id="${config.targetId}"]`);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
            else setTargetRect(null);
        } else {
            setTargetRect(null);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / 1300, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            setAnimatedRadius(2000 - (2000 - targetR) * easeOut);
            if (progress < 1) requestAnimationFrame(animate);
        };
        requestAnimationFrame(animate);
    }, [!!targetRect]);

    if (!config) return null;

    const { top = 0, left = 0, width = 0, height = 0 } = targetRect || {};
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';
    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top':
            pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' };
            iconRotation = 'rotate(180deg)';
            animationClass = 'animate-bounce-reverse';
            containerLayout = 'flex-col-reverse';
            labelMargin = 'mb-3';
            break;
        case 'bottom':
            pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' };
            iconRotation = 'rotate(0deg)';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
        case 'left':
            pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' };
            iconRotation = 'rotate(90deg)';
            animationClass = 'animate-bounce-x-reverse';
            containerLayout = 'flex-row-reverse';
            labelMargin = 'mr-3';
            break;
        case 'right':
            pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' };
            iconRotation = 'rotate(-90deg)';
            animationClass = 'animate-bounce-x';
            containerLayout = 'flex-row';
            labelMargin = 'ml-3';
            break;
    }

    // 대화 위주의 안내 단계에서는 배경 암전 효과를 숨깁니다.
    const isDialogueStep = step === 'BROWSE_GOODS_GUIDE' || step === 'GARRICK_AFTER_PURCHASE_DIALOG' || step === 'LEAVE_MARKET_GUIDE';

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden">
            {/* Visual Darkening Mask */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs>
                    <mask id="m-mask">
                        <rect width="100%" height="100%" fill="white" />
                        {targetRect && <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />}
                    </mask>
                </defs>
                <rect 
                    width="100%" 
                    height="100%" 
                    fill="rgba(0,0,0,0.75)" 
                    mask="url(#m-mask)" 
                    className={`transition-opacity duration-700 ${isDialogueStep ? 'opacity-0' : 'opacity-100'}`}
                />
            </svg>

            {/* Logical Interaction Walls (Blocking 4 sides around the target) */}
            {targetRect && (
                <div className="absolute inset-0 pointer-events-none">
                    {/* Top wall */}
                    <div className="absolute top-0 left-0 w-full pointer-events-auto" style={{ height: top }} />
                    {/* Bottom wall */}
                    <div className="absolute left-0 w-full pointer-events-auto" style={{ top: top + height, bottom: 0 }} />
                    {/* Left wall */}
                    <div className="absolute top-0 left-0 pointer-events-auto" style={{ top, height, width: left }} />
                    {/* Right wall */}
                    <div className="absolute top-0 pointer-events-auto" style={{ top, height, left: left + width, right: 0 }} />
                </div>
            )}

            {targetRect && (
                <div className="absolute animate-in fade-in zoom-in-95 duration-300" style={pointerStyles}>
                    <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                        <Pointer className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]" style={{ transform: iconRotation }} />
                        <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase tracking-widest rounded-full shadow-2xl border-2 border-amber-400 whitespace-nowrap`}>
                            {config.label}
                        </div>
                    </div>
                </div>
            )}

            {script && (
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[90vw] max-w-4xl pointer-events-none z-[5000]">
                    <DialogueBox 
                        speaker={script.speaker} 
                        text={script.text} 
                        options={
                            step === 'BROWSE_GOODS_GUIDE' 
                                ? [{ label: "Browse", action: () => actions.setTutorialStep('FURNACE_GUIDE'), variant: 'primary' }] 
                                : step === 'GARRICK_AFTER_PURCHASE_DIALOG' 
                                    ? [{ label: "Talk", action: () => actions.setTutorialStep('LEAVE_MARKET_GUIDE'), variant: 'primary' }] 
                                    : []
                        } 
                        className="w-full relative pointer-events-auto"
                    />
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect, useCallback, useLayoutEffect, useMemo } from 'react';
import Header from './Header';
import { InventoryDisplay } from './InventoryDisplay';
import { Anvil, Package, ShoppingBag, Coins, Beer, Map as MapIcon, Activity, ChevronLeft, ChevronRight, Pointer, Lock as LockIcon, FastForward, AlertCircle } from 'lucide-react';
import { useGame } from '../context/GameContext';

// Import Background Services
import { useShopService } from '../services/shop/shop-service';
import { useDungeonService } from '../services/dungeon/dungeon-service';

// Import Tabs
import ForgeTab from './tabs/forge/ForgeTab';
import ShopTab from './tabs/shop/ShopTab';
import TavernTab from './tabs/tavern/TavernTab';
import MarketTab from './tabs/market/MarketTab';
import DungeonTab from './tabs/Dungeon/DungeonTab';
import SimulationTab from './tabs/Simulation/SimulationTab';

// Import Modals
import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import TierUnlockModal from './modals/TierUnlockModal';
import SettingsModal from './modals/SettingsModal';
import TutorialScene from './tutorial/TutorialScene';
import DialogueBox from './DialogueBox';
import ConfirmationModal from './modals/ConfirmationModal';
import TutorialCompleteModal from './modals/TutorialCompleteModal';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

type TutorialDirection = 'top' | 'bottom' | 'left' | 'right' | 'topleft' | 'topright' | 'bottomleft' | 'bottomright';
interface StepConfig {
    targetId: string;
    label: string;
    direction: TutorialDirection;
}

const TUTORIAL_STEPS_CONFIG: Record<string, StepConfig> = {
    MARKET_GUIDE: { targetId: 'MARKET_TAB', label: 'Visit the Market', direction: 'bottom' },
    FORGE_TAB_GUIDE: { targetId: 'FORGE_TAB', label: 'Open Forge', direction: 'bottom' },
    SELECT_SWORD_GUIDE: { targetId: 'SWORD_RECIPE', label: 'Select Sword', direction: 'bottom' },
    START_FORGING_GUIDE: { targetId: 'START_FORGING_BUTTON', label: 'Start Forging', direction: 'right' },
    FINALIZE_FORGE_GUIDE: { targetId: 'FINALIZE_BUTTON', label: 'Complete Forge', direction: 'bottom' },
    OPEN_SHOP_TAB_GUIDE: { targetId: 'SHOP_TAB', label: 'Open Shop', direction: 'bottom' },
    OPEN_SHOP_SIGN_GUIDE: { targetId: 'SHOP_SIGN', label: 'Open the Shop', direction: 'bottom' },
};

const TUTORIAL_CONTEXT_SCRIPTS: Record<string, { speaker: string, text: string }> = {
    MARKET_GUIDE: { speaker: "Lockhart", text: "A forge without a roar is just a cold pile of stone. There should be a replacement furnace at the Market... let's head there." },
    FORGE_TAB_GUIDE: { speaker: "Lockhart", text: "The furnace is set. The air smells of potential again. I should prepare to craft my first blade." },
    SELECT_SWORD_GUIDE: { speaker: "Lockhart", text: "A Bronze Shortsword. A simple pattern, but a reliable test for this new unit." },
    OPEN_SHOP_TAB_GUIDE: { speaker: "Lockhart", text: "A blade without a wielder is just cold metal. Let's see if any travelers seek Lockhart steel." },
    OPEN_SHOP_SIGN_GUIDE: { speaker: "Lockhart", text: "The forge is alive. The shop must follow. Flip the sign and let them come." },
};

const TutorialOverlay = ({ step }: { step: string }) => {
    const { state, actions } = useGame();
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const animRef = useRef<number | null>(null);

    const config = TUTORIAL_STEPS_CONFIG[step];
    const script = TUTORIAL_CONTEXT_SCRIPTS[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.querySelector(`[data-tutorial-id="${config.targetId}"]`);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) setTargetRect(rect);
            else setTargetRect(null);
        } else {
            setTargetRect(null);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        if (!targetRect) return; 
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const duration = 1300;
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            const nextR = 2000 - (2000 - targetR) * easeOut;
            setAnimatedRadius(nextR);
            if (progress < 1) animRef.current = requestAnimationFrame(animate);
        };
        animRef.current = requestAnimationFrame(animate);
        return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
    }, [config?.targetId, !!targetRect]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!config) return null;

    const { top = 0, left = 0, width = 0, height = 0 } = targetRect || {};
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';
    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top': pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' }; iconRotation = 'rotate(180deg)'; animationClass = 'animate-bounce-reverse'; containerLayout = 'flex-col-reverse'; labelMargin = 'mb-3'; break;
        case 'bottom': pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = ''; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
        case 'left': pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' }; iconRotation = 'rotate(90deg)'; animationClass = 'animate-bounce-x-reverse'; containerLayout = 'flex-row-reverse'; labelMargin = 'mr-3'; break;
        case 'right': pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' }; iconRotation = 'rotate(-90deg)'; animationClass = 'animate-bounce-x'; containerLayout = 'flex-row'; labelMargin = 'ml-3'; break;
        default: pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' }; iconRotation = ''; animationClass = 'animate-bounce'; containerLayout = 'flex-col'; labelMargin = 'mt-3'; break;
    }

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden">
            {/* Visual Darkening Mask */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs><mask id="tutorial-mask-layout"><rect width="100%" height="100%" fill="white" />{targetRect && <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />}</mask></defs>
                <rect width="100%" height="100%" fill={`rgba(0,0,0,0.75)`} mask="url(#tutorial-mask-layout)" />
            </svg>

            {/* Logical Interaction Walls (Blocking 4 sides around the target) */}
            {targetRect && (
                <div className="absolute inset-0 pointer-events-none">
                    {/* Top wall */}
                    <div className="absolute top-0 left-0 w-full pointer-events-auto" style={{ height: top }} />
                    {/* Bottom wall */}
                    <div className="absolute left-0 w-full pointer-events-auto" style={{ top: top + height, bottom: 0 }} />
                    {/* Left wall */}
                    <div className="absolute top-0 left-0 pointer-events-auto" style={{ top, height, width: left }} />
                    {/* Right wall */}
                    <div className="absolute top-0 pointer-events-auto" style={{ top, height, left: left + width, right: 0 }} />
                </div>
            )}

            {/* Pointer and Label */}
            {targetRect && (
                <div key={config.targetId} className="absolute animate-in fade-in zoom-in-95 duration-300" style={pointerStyles}>
                    <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                        <Pointer className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20" style={{ transform: iconRotation }} />
                        <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase rounded-full shadow-2xl border-2 border-amber-400`}>{config.label}</div>
                    </div>
                </div>
            )}

            {/* Dialogue Box Area */}
            {script && (
                <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl pointer-events-none z-[5000]">
                    <DialogueBox speaker={script.speaker} text={script.text} options={[]} className="w-full relative pointer-events-auto" />
                </div>
            )}
        </div>
    );
};

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const { state, actions } = useGame();
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showSkipConfirm, setShowSkipConfirm] = useState(false);
  const [isSleeping, setIsSleeping] = useState(false);
  const [isFadingOut, setIsFadingOut] = useState(false);
  const [zzzText, setZzzText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);
  const prevDayRef = useRef(state.stats.day);

  // Background Services
  useShopService();
  useDungeonService();

  useEffect(() => {
    if (state.stats.day > prevDayRef.current) {
        setIsSleeping(true); setIsFadingOut(false); setActiveTab('FORGE');
        const sleepTimer = setTimeout(() => {
            setIsFadingOut(true);
            setTimeout(() => { setIsSleeping(false); setIsFadingOut(false); actions.closeRest(); }, 1000); 
        }, 1000); 
        prevDayRef.current = state.stats.day;
        return () => clearTimeout(sleepTimer);
    }
    prevDayRef.current = state.stats.day;
  }, [state.stats.day, actions]);

  useEffect(() => {
    if (isSleeping && !isFadingOut) {
        const frames = ['z', 'zz', 'zzz', 'zz']; let idx = 0;
        const timer = setInterval(() => { setZzzText(frames[idx % frames.length]); idx++; }, 250);
        return () => clearInterval(timer);
    } else { setZzzText(''); }
  }, [isSleeping, isFadingOut]);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      setShowRightArrow(canScroll && Math.ceil(scrollLeft) < (scrollWidth - clientWidth - 2));
    }
  }, []);

  useLayoutEffect(() => { setTimeout(updateArrows, 100); }, [updateArrows, activeTab]);
  useEffect(() => { window.addEventListener('resize', updateArrows); return () => window.removeEventListener('resize', updateArrows); }, [updateArrows]);

  const completedExpeditionsCount = state.activeExpeditions.filter(exp => exp.status === 'COMPLETED').length;
  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;
  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);
  const unallocatedPointsCount = useMemo(() => state.knownMercenaries.filter(m => ['HIRED', 'ON_EXPEDITION', 'INJURED'].includes(m.status) && (m.bonusStatPoints || 0) > 0).length, [state.knownMercenaries]);

  const allTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'INVENTORY' as const, icon: Package, label: 'Storage' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern', badge: unallocatedPointsCount },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ];

  const isAnyTutorialActive = !!state.tutorialStep && state.hasCompletedPrologue && !state.isCrafting;

  // Dialogue steps mapping for MainGameLayout
  const dialogueContent = useMemo(() => {
    switch (state.tutorialStep) {
        case 'CRAFT_START_DIALOG':
            return {
                speaker: "Lockhart",
                text: "The heat is steady... I'll craft a Bronze Shortsword to test the unit.",
                nextStep: 'FORGE_TAB_GUIDE' as const
            };
        case 'CRAFT_RESULT_DIALOG':
            return {
                speaker: "Lockhart",
                text: "Higher mastery grants permanent bonuses. Let's finish this piece.",
                nextStep: 'FINALIZE_FORGE_GUIDE' as const
            };
        case 'SHOP_INTRO_DIALOG':
            return {
                speaker: "Lockhart",
                text: "The forge is alive. The shop must follow. Let's head to the Shop tab.",
                nextStep: 'OPEN_SHOP_TAB_GUIDE' as const
            };
        default:
            return null;
    }
  }, [state.tutorialStep]);

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden px-safe selection:bg-amber-500/30">
      {/* Tutorial Scenes Layer (Renders instead of early return to fix Hook violation) */}
      {state.activeTutorialScene && !['MARKET', 'SMITHING'].includes(state.activeTutorialScene) && (
        <div className="fixed inset-0 z-[5000]">
          <TutorialScene />
        </div>
      )}

      {isSleeping && <div className={`fixed inset-0 z-[10000] bg-black transition-opacity ${isFadingOut ? 'opacity-0 duration-[1000ms]' : 'opacity-100'}`}>{!isFadingOut && <div className="absolute inset-0 flex flex-col items-center justify-center gap-4"><span className="text-amber-500 font-serif italic text-5xl md:text-7xl">{zzzText}</span><span className="text-stone-700 font-black uppercase text-[10px]">Resting...</span></div>}</div>}
      {isAnyTutorialActive && <div className="fixed top-4 right-4 z-[6000]"><button onClick={() => setShowSkipConfirm(true)} className="flex items-center gap-1.5 px-3 py-1.5 bg-stone-900 border border-stone-700 text-stone-300 rounded-full text-[10px] uppercase font-black shadow-2xl backdrop-blur-md active:scale-95"><FastForward className="w-3 h-3" /> Skip Tutorial</button></div>}
      {isAnyTutorialActive && state.tutorialStep && TUTORIAL_STEPS_CONFIG[state.tutorialStep] && <TutorialOverlay step={state.tutorialStep} />}

      {dialogueContent && (
        <div className="fixed inset-0 z-[2500] flex flex-col justify-end items-center pb-6 md:pb-12 px-4 pointer-events-none">
            {/* Blocking Overlay for Tutorial Dialogue Steps */}
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm pointer-events-auto animate-in fade-in duration-500" />

            <div className="w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto z-10">
                <DialogueBox 
                    speaker={dialogueContent.speaker} 
                    text={dialogueContent.text} 
                    options={[{ label: "Continue", action: () => actions.setTutorialStep(dialogueContent.nextStep), variant: 'primary' }]} 
                />
            </div>
        </div>
      )}

      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'opacity-100'}`}><Header activeTab={activeTab} onTabChange={setActiveTab} onSettingsClick={() => setIsSettingsOpen(true)} /><div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden h-11 md:h-14"><div ref={scrollRef} onScroll={updateArrows} className="flex overflow-x-auto no-scrollbar flex-1 touch-pan-x snap-x scroll-smooth">{allTabs.map(tab => <button onClick={() => { if (!state.unlockedTabs.includes(tab.id) && !(tab.id === 'SHOP' && state.tutorialStep)) return actions.showToast("Facility locked."); if (state.tutorialStep === 'MARKET_GUIDE' && tab.id === 'MARKET') { actions.setTutorialStep('BROWSE_GOODS_GUIDE'); actions.setTutorialScene('MARKET'); } else if (state.tutorialStep === 'FORGE_TAB_GUIDE' && tab.id === 'FORGE') actions.setTutorialStep('SELECT_SWORD_GUIDE'); else if (state.tutorialStep === 'OPEN_SHOP_TAB_GUIDE' && tab.id === 'SHOP') actions.setTutorialStep('OPEN_SHOP_SIGN_GUIDE'); setActiveTab(tab.id); }} key={tab.id} data-tutorial-id={tab.id === 'MARKET' ? 'MARKET_TAB' : tab.id === 'FORGE' ? 'FORGE_TAB' : tab.id === 'SHOP' ? 'SHOP_TAB' : undefined} className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all shrink-0 ${activeTab === tab.id ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-[2100]' : 'border-transparent text-stone-500'} ${!state.unlockedTabs.includes(tab.id) && !(tab.id === 'SHOP' && state.tutorialStep) ? 'grayscale opacity-40' : ''}`}><tab.icon className="w-4 h-4 md:w-5 md:h-5" /><span className="font-bold text-[10px] md:text-sm uppercase">{tab.label}</span>{tab.badge ? <div className="absolute top-1 right-1 flex h-4 w-4 items-center justify-center rounded-full text-[8px] font-black text-white bg-red-600">{tab.badge}</div> : null}</button>)}</div></div></div>
      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0"><div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}><ForgeTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}><ShopTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'INVENTORY' ? 'block' : 'hidden'}`}><InventoryDisplay /></div><div className={`h-full w-full ${activeTab === 'MARKET' ? 'block' : 'hidden'}`}><MarketTab onNavigate={setActiveTab} /></div><div className={`h-full w-full ${activeTab === 'TAVERN' ? 'block' : 'hidden'}`}><TavernTab activeTab={activeTab} /></div><div className={`h-full w-full ${activeTab === 'DUNGEON' ? 'block' : 'hidden'}`}><DungeonTab /></div><div className={`h-full w-full ${activeTab === 'SIMULATION' ? 'block' : 'hidden'}`}><SimulationTab /></div></main>
      {state.toast?.visible && <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-bottom-4 pointer-events-none"><div onClick={actions.hideToast} className="bg-stone-900 border-2 border-amber-600/50 px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 pointer-events-auto cursor-pointer"><span className="text-stone-100 font-black text-xs md:text-sm uppercase tracking-widest">{state.toast.message}</span></div></div>}
      <EventModal /><SleepModal /><JournalModal /><DungeonResultModal /><CraftingResultModal /><SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} /><TierUnlockModal /><TutorialCompleteModal /><ConfirmationModal isOpen={showSkipConfirm} title="Skip?" message="Unlock all systems immediately?" onConfirm={() => { actions.completeTutorial(); setShowSkipConfirm(false); }} onCancel={() => setShowSkipConfirm(false)} isDanger />
    </div>
  );
};

export default MainGameLayout;

// Added React import to resolve 'Cannot find namespace React' errors
import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EquipmentCategory, EquipmentItem } from '../../../../types';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../../../config/mastery-config';
import { materials } from '../../../../data/materials';
import { getSmithingLevel, getUnlockedTier, getEnergyCost } from '../../../../utils/craftingLogic';

export const useForge = (onNavigate: (tab: any) => void) => {
  const { state, actions } = useGame();
  const { inventory, stats, isCrafting, craftingMastery, unlockedRecipes, tutorialStep, forgeTemperature, lastForgeTime } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [isSkillsExpanded, setIsSkillsExpanded] = useState(false);
  const [expandedSubCat, setExpandedSubCat] = useState<string | null>('SWORD');
  const [favorites, setFavorites] = useState<string[]>([]);
  const [isFavExpanded, setIsFavExpanded] = useState(true);
  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [quickCraftProgress, setQuickCraftProgress] = useState<number | null>(null);

  const smithingLevel = getSmithingLevel(stats.smithingExp);
  const workbenchLevel = getSmithingLevel(stats.workbenchExp);
  const unlockedSmithingTier = getUnlockedTier(smithingLevel);
  const unlockedWorkbenchTier = getUnlockedTier(workbenchLevel);

  const getInventoryCount = useCallback((id: string) => {
    return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const currentResidualTemp = useMemo(() => {
    const GLOBAL_COOLING_RATE_PER_SEC = 5;
    const timeDiffSec = (Date.now() - (lastForgeTime || 0)) / 1000;
    return Math.max(0, (forgeTemperature || 0) - (timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC));
  }, [forgeTemperature, lastForgeTime]);

  const canEnterForge = useMemo(() => {
    if (!selectedItem) return false;
    if (selectedItem.craftingType === 'FORGE') {
      const hasHeat = currentResidualTemp > 0;
      const hasFuel = getInventoryCount('charcoal') > 0;
      const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';
      return hasFurnace && (hasFuel || hasHeat || isTutorialForging);
    }
    return hasWorkbench;
  }, [selectedItem, hasFurnace, hasWorkbench, currentResidualTemp, getInventoryCount, tutorialStep]);

  const requiredEnergy = useMemo(() => {
    if (!selectedItem) return 20;
    const count = craftingMastery[selectedItem.id] || 0;
    return getEnergyCost(selectedItem, count);
  }, [selectedItem, craftingMastery]);

  const visibleItems = useMemo(() => {
    return EQUIPMENT_ITEMS.filter(item => {
      const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
      if (!isUnlocked) return false;
      const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
      if (item.tier > myTier) return false;
      const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
      return subCatDef?.categoryId === activeCategory;
    });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const favoriteItems = useMemo(() => visibleItems.filter(item => favorites.includes(item.id)), [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
    const groups: Record<string, EquipmentItem[]> = {};
    visibleItems.forEach(item => {
      if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
      groups[item.subCategoryId].push(item);
    });
    return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
    return EQUIPMENT_SUBCATEGORIES.filter(sc => 
      sc.categoryId === activeCategory && (groupedItems[sc.id]?.length || 0) > 0
    );
  }, [activeCategory, groupedItems]);

  // Added masteryInfo calculation
  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);
    setExpandedSubCat(cat === 'WEAPON' ? 'SWORD' : 'HELMET');
  }, []);

  const startCrafting = useCallback(() => {
    if (!selectedItem) return;
    const isRequirementMet = selectedItem.craftingType === 'FORGE' ? hasFurnace : hasWorkbench;

    if (!isRequirementMet) {
      actions.triggerEvent({
        id: 'NONE',
        title: 'Installation Required',
        description: `Requires ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'}.`,
        options: [{ label: 'Visit Market', action: () => onNavigate('MARKET') }, { label: 'Stay here', action: () => {} }]
      });
      return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0) {
      actions.showToast("Insufficient materials.");
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
      actions.triggerEnergyHighlight();
      return;
    }

    actions.startCrafting(selectedItem);
    setIsPanelOpen(false);
  }, [selectedItem, hasFurnace, hasWorkbench, getInventoryCount, stats.energy, craftingMastery, actions, onNavigate]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
      actions.finishCrafting(selectedItem, score, bonus);
      // Fix: Updated 'CRAFT_RESULT_PROMPT' to 'CRAFT_RESULT_DIALOG' to match type definition
      if (tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1') {
        actions.setTutorialStep('CRAFT_RESULT_DIALOG');
      }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleQuickCraft = useCallback(() => {
    if (!selectedItem) return;
    setQuickCraftProgress(0);
    const duration = 1500;
    const timer = setInterval(() => {
      setQuickCraftProgress(prev => {
        if (prev === null || prev >= 100) {
          clearInterval(timer);
          actions.startCrafting(selectedItem);
          actions.finishCrafting(selectedItem, 80, 0, 0.7);
          return null;
        }
        return prev + 2;
      });
    }, 30);
  }, [selectedItem, actions]);

  const updateTooltipPosition = (x: number, y: number) => {
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;
    let finalX = x + 20;
    let finalY = y + 20;
    if (finalX + 240 > viewportW) finalX = x - 260;
    if (finalY + 160 > viewportH) finalY = y - 180;
    setTooltipPos({ x: finalX, y: finalY });
  };

  // Added missing handlers
  const handleSelectItem = useCallback((item: EquipmentItem) => {
      setSelectedItem(item);
      if (tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  }, [tutorialStep, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  return {
    state,
    actions,
    isCrafting,
    activeCategory,
    selectedItem,
    isPanelOpen,
    isSkillsExpanded,
    expandedSubCat,
    favorites,
    isFavExpanded,
    hoveredItem,
    tooltipPos,
    quickCraftProgress,
    smithingLevel,
    workbenchLevel,
    unlockedSmithingTier,
    unlockedWorkbenchTier,
    visibleSubCats,
    groupedItems,
    favoriteItems,
    canEnterForge,
    requiredEnergy: selectedItem ? getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0) : 20,
    getInventoryCount,
    masteryInfo,
    handlers: {
      setActiveCategory,
      setSelectedItem,
      setIsPanelOpen,
      setIsSkillsExpanded,
      setExpandedSubCat,
      setFavorites,
      setIsFavExpanded,
      setHoveredItem,
      setTooltipPos,
      handleCategoryChange,
      startCrafting,
      handleMinigameComplete,
      handleQuickCraft,
      updateTooltipPosition,
      handleSelectItem,
      handleMouseEnter,
      handleMouseMove,
      handleMouseLeave,
      toggleSubCategory: (id: string) => setExpandedSubCat(prev => prev === id ? null : id),
      toggleFavorite: (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
      }
    }
  };
};

import { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../../context/GameContext';
import { materials } from '../../../../data/materials';
import { MARKET_CATALOG } from '../../../../data/market/index';
import { InventoryItem } from '../../../../types/inventory';
import { GAME_CONFIG } from '../../../../config/game-config';

export type MarketViewMode = 'INTERACTION' | 'CATALOG';

export interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useMarket = (onNavigate: (tab: any) => void) => {
    const { state, actions } = useGame();
    const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
    const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");
    const [cart, setCart] = useState<Record<string, number>>({});
    const [isCartOpen, setIsCartOpen] = useState(false);
    const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});
    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [showGiftModal, setShowGiftModal] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);
    const [collapsedSections, setCollapsedSections] = useState<string[]>([]);

    const { hasFurnace, hasWorkbench } = state.forge;
    const currentTier = state.stats.tierLevel;

    // Tutorial Sync
    useEffect(() => {
        if (state.tutorialStep === 'FURNACE_GUIDE') setViewMode('CATALOG');
        else if (state.tutorialStep === 'GARRICK_AFTER_PURCHASE_DIALOG') setViewMode('INTERACTION');
    }, [state.tutorialStep]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const prevAffinityRef = useRef<number>(state.garrickAffinity);
    useEffect(() => {
        if (state.garrickAffinity > prevAffinityRef.current) {
            spawnHearts(Math.min(10, (state.garrickAffinity - prevAffinityRef.current) * 2));
        }
        prevAffinityRef.current = state.garrickAffinity;
    }, [state.garrickAffinity, spawnHearts]);

    const cartItemCount = useMemo(() => Object.values(cart).reduce((a: number, b: number) => a + b, 0), [cart]);

    const totalCost = useMemo(() => {
        // Explicitly type entries to avoid arithmetic errors with 'unknown'
        return Object.entries(cart).reduce((total: number, entry: [string, number]) => {
            const [id, count] = entry;
            return total + ((materials[id]?.baseValue ?? 0) * count);
        }, 0);
    }, [cart]);

    const categorizedMarketItems = useMemo(() => {
        if (state.tutorialStep === 'FURNACE_GUIDE') {
            const config = MARKET_CATALOG.find(c => c.id === 'furnace');
            return config ? [{ id: 'fac', name: 'Facilities', items: [{ ...config, meta: materials['furnace'] }] }] : [];
        }

        const groups: Record<string, any[]> = { t1: [], t2: [], t3: [], t4: [], sup: [], tech: [], fac: [] };
        MARKET_CATALOG.forEach(config => {
            const meta = materials[config.id];
            if (!meta) return;
            const isOwned = (config.id === 'furnace' && hasFurnace) || (config.id === 'workbench' && hasWorkbench);
            if (config.type === 'FACILITY' && isOwned) return;
            if (config.type === 'RESOURCE' && (meta.tier || 1) > currentTier) return;

            const payload = { ...config, meta };
            if (config.type === 'RESOURCE') groups[`t${meta.tier || 1}`].push(payload);
            else if (config.type === 'SUPPLY') groups.sup.push(payload);
            else if (config.type === 'TECHNIQUE') groups.tech.push(payload);
            else if (config.type === 'FACILITY') groups.fac.push(payload);
        });

        return [
            { id: 'tier1', name: 'Tier 1 Resources', items: groups.t1 },
            { id: 'tier2', name: 'Tier 2 Resources', items: groups.t2 },
            { id: 'tier3', name: 'Tier 3 Resources', items: groups.t3 },
            { id: 'tier4', name: 'Tier 4 Resources', items: groups.t4 },
            { id: 'sup', name: 'Potions & Supplies', items: groups.sup },
            { id: 'tech', name: 'Techniques', items: groups.tech },
            { id: 'fac', name: 'Facilities', items: groups.fac },
        ].filter(g => g.items.length > 0);
    }, [hasFurnace, hasWorkbench, currentTier, state.tutorialStep]);

    const addToCart = (itemId: string, amount: number = 1) => {
        if (itemId === 'scroll_t2' && state.garrickAffinity < 20) {
            setDialogue("Requires 20 Affinity with Garrick.");
            return false;
        }
        if (itemId === 'scroll_t3' && state.garrickAffinity < 40) {
            setDialogue("Requires 40 Affinity with Garrick.");
            return false;
        }
        const available = (state.marketStock[itemId] || 0) - (cart[itemId] || 0);
        if (available <= 0) return false;
        const addCount = Math.min(amount, available);

        if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') actions.setTutorialStep('OPEN_SHOPPING_CART');

        setCart(prev => ({ ...prev, [itemId]: (prev[itemId] || 0) + addCount }));
        return true;
    };

    const removeFromCart = (itemId: string) => {
        setCart(prev => {
            const next = { ...prev };
            if (next[itemId] > 1) next[itemId]--;
            else delete next[itemId];
            return next;
        });
    };

    const handleBuy = () => {
        if (cartItemCount === 0 || totalCost > state.stats.gold) return;
        if (state.tutorialStep === 'PAY_NOW') {
            if (cart['furnace']) actions.setTutorialStep('GARRICK_AFTER_PURCHASE_DIALOG');
            else actions.setTutorialStep(null);
        }
        actions.buyItems(Object.entries(cart).map(([id, count]) => ({ id, count })), totalCost);
        setCart({});
        setIsCartOpen(false);
    };

    return {
        state, actions, viewMode, setViewMode, dialogue, setDialogue, cart, isCartOpen, setIsCartOpen,
        itemMultipliers, setItemMultipliers, floatingHearts, showGiftModal, setShowGiftModal,
        pendingGiftItem, setPendingGiftItem, collapsedSections, setCollapsedSections,
        cartItemCount, totalCost, categorizedMarketItems,
        handlers: {
            handleTalk: () => {
                if (!state.talkedToGarrickToday) actions.talkGarrick();
                const lines = ["Roads are dangerous lately.", "Your grandfather was a legend.", "Need rarity? Prove your worth."];
                setDialogue(lines[Math.floor(Math.random() * lines.length)]);
            },
            handleGiftInit: (item: InventoryItem) => {
                if (item.isLocked) return actions.showToast("Item is locked.");
                setPendingGiftItem(item); setShowGiftModal(false);
                setDialogue(`"Would you like this, Garrick?"`);
            },
            handleConfirmGift: () => {
                if (!pendingGiftItem) return;
                actions.giftGarrick({ itemId: pendingGiftItem.id });
                setPendingGiftItem(null); setDialogue("For me? Hah, you're a thoughtful one.");
            },
            addToCart, removeFromCart, deleteFromCart: (id: string) => setCart(prev => { const n = {...prev}; delete n[id]; return n; }),
            handleBuy, handleBackToForge: () => {
                if (state.tutorialStep === 'LEAVE_MARKET_GUIDE') {
                    actions.setTutorialScene('FURNACE_RESTORED');
                    actions.setTutorialStep(null);
                }
                onNavigate('FORGE');
            }
        }
    };
};

import React from 'react';
import { ShoppingCart, X, Minus, Plus, ShoppingBag, Coins } from 'lucide-react';
import { materials } from '../../../../data/materials';
import { getAssetUrl } from '../../../../utils';

interface ShoppingCartDrawerProps {
    isOpen: boolean;
    cart: Record<string, number>;
    total: number;
    gold: number;
    onRemove: (id: string) => void;
    onAdd: (id: string, count: number) => void;
    onDelete: (id: string) => void;
    onBuy: () => void;
}

export const ShoppingCartDrawer: React.FC<ShoppingCartDrawerProps> = ({ isOpen, cart, total, gold, onRemove, onAdd, onDelete, onBuy }) => {
    return (
        <div className={`h-full bg-stone-950/80 border-l border-stone-800 shadow-2xl flex flex-col transition-all duration-500 ${isOpen ? 'w-48 md:w-72' : 'w-0 overflow-hidden border-none'}`}>
            <div className="bg-stone-850 p-4 border-b border-stone-800 shrink-0"><h3 className="font-serif font-black text-stone-100 uppercase truncate">Cart Contents</h3></div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {Object.entries(cart).length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center opacity-10"><ShoppingCart className="w-10 h-10 mb-2"/><p className="text-[10px] font-black uppercase">Empty</p></div>
                ) : (
                    // Added explicit typing to cart entry destructuring
                    Object.entries(cart).map(([id, count]: [string, number]) => {
                        const meta = materials[id];
                        return (
                            <div key={id} className="bg-stone-900/60 p-2 rounded-xl border border-stone-800">
                                <div className="flex items-center gap-2 mb-2">
                                    <div className="w-10 h-10 bg-stone-950 rounded-lg flex items-center justify-center shrink-0 shadow-inner"><img src={getAssetUrl(`${id}.png`)} className="w-8 h-8 object-contain" /></div>
                                    <div className="flex-1 min-w-0"><div className="text-stone-100 font-bold text-[10px] truncate">{meta?.name || id}</div><div className="text-amber-600 font-mono text-[9px] font-black">{ (meta?.baseValue || 0) * count } G</div></div>
                                    <button onClick={() => onDelete(id)} className="text-stone-600 hover:text-red-500 transition-colors"><X className="w-3.5 h-3.5" /></button>
                                </div>
                                <div className="flex items-center justify-between bg-black/40 rounded p-1">
                                    <span className="text-[10px] font-mono font-black text-stone-200 ml-1">{count}</span>
                                    <div className="flex gap-1"><button onClick={() => onRemove(id)} className="w-6 h-6 bg-stone-800 rounded border border-stone-700 text-stone-300 active:scale-90"><Minus className="w-3.5 h-3.5 mx-auto" /></button><button onClick={() => onAdd(id, 1)} className="w-6 h-6 bg-stone-800 rounded border border-stone-700 text-stone-300 active:scale-90"><Plus className="w-3.5 h-3.5 mx-auto" /></button></div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
            <div className="bg-stone-850 p-4 border-t border-stone-800 space-y-2 shrink-0">
                <div className="flex justify-between items-center text-[10px] text-stone-500 font-bold uppercase"><span>Total</span><span className={`text-lg font-mono font-black ${total > gold ? 'text-red-500' : 'text-emerald-400'}`}>{total}G</span></div>
                <button onClick={onBuy} disabled={total === 0 || total > gold} className={`w-full py-3 rounded-xl font-black text-[10px] transition-all flex items-center justify-center gap-2 shadow-xl ${total > gold ? 'bg-red-900/60 text-red-100 border border-red-500/50' : total === 0 ? 'bg-stone-800 text-stone-600 opacity-60' : 'bg-amber-600 hover:bg-amber-500 text-white'}`}><ShoppingBag className="w-4 h-4" /><span>{total > gold ? 'Shortage' : 'Buy Now'}</span></button>
            </div>
        </div>
    );
};

import { useEffect, useRef } from 'react';
import { useGame } from '../../context/GameContext';
import { generateShopRequest } from '../../utils/shopUtils';
import { calculateMaxHp, calculateMaxMp } from '../../models/Stats';
import { SHOP_CONFIG } from '../../config/shop-config';

/**
 * useShopService
 * Handles the background logic for the shop:
 * 1. Generating customers at random intervals (Configurable).
 * 2. Managing the queue.
 * 3. Handling customer patience timeouts.
 */
export const useShopService = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, visitorsToday } = state;

    const arrivalTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const patienceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // --- 1. Arrival Logic ---
    useEffect(() => {
        if (!isShopOpen) {
            if (arrivalTimerRef.current) clearTimeout(arrivalTimerRef.current);
            return;
        }

        const scheduleNextArrival = () => {
            // Tutorial check: Block arrivals if we are in the middle of tutorial dialogues
            // Added SELL_ITEM_GUIDE to block other customers while Pip is the focus
            const isTutorialSignStep = state.tutorialStep === 'SELL_ITEM_GUIDE';
            const isMidDialogue = state.tutorialStep === 'PIP_PRAISE_DIALOG' || 
                                 state.tutorialStep === 'DRAGON_TALK_DIALOG' || 
                                 state.tutorialStep === 'TUTORIAL_END_DIALOG';

            if (isMidDialogue || isTutorialSignStep) {
                if (arrivalTimerRef.current) clearTimeout(arrivalTimerRef.current);
                return;
            }

            const interval = Math.random() * SHOP_CONFIG.ARRIVAL.VARIANCE_MS + SHOP_CONFIG.ARRIVAL.MIN_INTERVAL_MS;

            arrivalTimerRef.current = setTimeout(() => {
                // Tutorial logic: Always bring Pip the Green if in the shop guide
                // But only if we haven't served him yet (handled by the step check)
                if (state.tutorialStep === 'SELL_ITEM_GUIDE' && activeCustomer === null && shopQueue.length === 0) {
                    const pip = state.knownMercenaries.find(m => m.id === 'pip_green');
                    if (pip) {
                        const customer = generateShopRequest(pip);
                        customer.request.requestedId = 'sword_bronze_t1';
                        customer.request.dialogue = "Lockhart! I heard you fixed the furnace. I've been training with a wooden stick... Do you have a real Bronze Shortsword for sale?";
                        customer.request.price = 550;
                        actions.enqueueCustomer(customer);
                    }
                    return;
                }

                // Normal Candidate filtering
                const validCandidates = state.knownMercenaries.filter(m => 
                    !visitorsToday.includes(m.id) && 
                    !['ON_EXPEDITION', 'IN_JURED', 'DEAD'].includes(m.status)
                );

                if (validCandidates.length === 0) {
                    scheduleNextArrival();
                    return;
                }

                const selectedMerc = validCandidates[Math.floor(Math.random() * validCandidates.length)];
                const maxHp = calculateMaxHp(selectedMerc.stats, selectedMerc.level);
                const maxMp = calculateMaxMp(selectedMerc.stats, selectedMerc.level);

                const visitingMerc = {
                    ...selectedMerc,
                    currentHp: maxHp,
                    currentMp: maxMp,
                    maxHp,
                    maxMp
                };

                const customer = generateShopRequest(visitingMerc);
                actions.enqueueCustomer(customer);

                scheduleNextArrival();
            }, interval);
        };

        scheduleNextArrival();

        return () => {
            if (arrivalTimerRef.current) clearTimeout(arrivalTimerRef.current);
        };
    }, [isShopOpen, visitorsToday, state.knownMercenaries, state.tutorialStep, activeCustomer, shopQueue.length, actions]);

    // --- 2. Queue Processing Logic ---
    useEffect(() => {
        if (!isShopOpen) return;

        // CRITICAL: Block normal queue processing if tutorial dialogues are active.
        // Specifically prevents nextCustomer() during TUTORIAL_END_DIALOG when Pip is gone.
        const isTutorialDialogueActive = !!state.tutorialStep && [
            'PIP_PRAISE_DIALOG', 
            'DRAGON_TALK_DIALOG', 
            'TUTORIAL_END_DIALOG'
        ].includes(state.tutorialStep);

        if (!activeCustomer && shopQueue.length > 0 && !isTutorialDialogueActive) {
            const t = setTimeout(() => {
                actions.nextCustomer();
            }, SHOP_CONFIG.QUEUE_PROCESS_DELAY_MS);
            return () => clearTimeout(t);
        }
    }, [isShopOpen, activeCustomer, shopQueue, actions, state.tutorialStep]);

    // --- 3. Patience Timer Logic ---
    useEffect(() => {
        // Disable patience timer during tutorial to prevent Pip from leaving
        const isTutorialDialogue = state.tutorialStep === 'SELL_ITEM_GUIDE' || 
                                  state.tutorialStep === 'PIP_PRAISE_DIALOG' || 
                                  state.tutorialStep === 'DRAGON_TALK_DIALOG';

        if (!activeCustomer || isTutorialDialogue) {
            if (patienceTimerRef.current) clearTimeout(patienceTimerRef.current);
            return;
        }

        patienceTimerRef.current = setTimeout(() => {
            actions.dismissCustomer();
        }, SHOP_CONFIG.PATIENCE_MS);

        return () => {
            if (patienceTimerRef.current) clearTimeout(patienceTimerRef.current);
        };
    }, [activeCustomer, actions, state.tutorialStep]);
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
  dataTutorialId?: string; // 추가: 튜토리얼 추적을 위한 ID
}

interface ItemDetail {
  icon: string;
  imageUrl?: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

// Added speakerAvatar to DialogueBoxProps to resolve TS error in AssaultNavigator.tsx
interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar // Destructure speakerAvatar prop
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-help relative inline-block pointer-events-auto"
            onMouseEnter={(e) => { updateTooltipPosition(e); setShowItemTooltip(true); }}
            onMouseLeave={() => setShowItemTooltip(false)}
            onClick={(e) => { e.stopPropagation(); updateTooltipPosition(e); setShowItemTooltip(!showItemTooltip); }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  // Tooltip content rendered via Portal
  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-none p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className="w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 border-stone-800 flex items-center justify-center shadow-inner shrink-0 overflow-hidden">
          {itemDetail.imageUrl ? (
            <img src={itemDetail.imageUrl} className="w-7 h-7 md:w-11 md:h-11 object-contain" alt="item" />
          ) : (
            <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className="flex items-center gap-1 text-emerald-400 font-mono font-black text-xs md:text-xl">
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        {itemDetail.isUnlocked ? (
          <div className="grid gap-1">
            {itemDetail.requirements?.map(req => {
              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);
              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="py-4 md:py-6 flex flex-col items-center justify-center bg-black/40 rounded-xl border-2 border-dashed border-stone-800 animate-in fade-in duration-500">
            <div className="relative">
                <span className="text-4xl md:text-7xl font-serif text-stone-800 font-black animate-pulse">?</span>
                <Lock className="absolute -top-0.5 -right-0.5 w-3 h-3 md:w-5 md:h-5 text-stone-700" />
            </div>
            <div className="mt-2 md:mt-4 flex flex-col items-center text-center px-2">
              <span className="text-[7px] md:text-[10px] text-stone-600 font-black uppercase tracking-widest italic leading-none">Unknown</span>
              <p className="mt-1 text-[6px] md:text-[8px] text-stone-700 font-bold max-w-[120px] md:max-w-[160px] uppercase leading-relaxed tracking-tighter">
                Requires Knowledge Scroll
              </p>
            </div>
          </div>
        )}
      </div>

      {/* Tooltip Arrow */}
      <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] md:border-l-[12px] border-l-transparent border-r-[8px] md:border-r-[12px] border-r-transparent border-t-[8px] md:border-t-[12px] border-t-stone-900/98"></div>
    </div>,
    document.body
  );

  return (
    <div className={className}>
      {tooltipElement}

      <div 
        className="w-full h-[22dvh] min-h-[120px] md:h-[28vh] md:min-h-[160px] bg-stone-950/25 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_25px_70px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-8 fade-in duration-500 ring-1 ring-white/10"
      >
        <div className="bg-stone-900/20 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-20 md:w-48 shrink-0 justify-center">
          <div className="w-9 h-9 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/30 to-stone-800/40 border border-amber-600/30 flex items-center justify-center shadow-inner ring-1 ring-white/5 overflow-hidden">
             {/* Render speaker avatar if provided, otherwise use generic User icon */}
             {speakerAvatar ? (
               <img src={speakerAvatar} className="w-full h-full object-cover" alt={speaker} />
             ) : (
               <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/90 drop-shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
             )}
          </div>
          <div className="flex flex-col items-center overflow-hidden w-full">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full px-1">
                {speaker}
              </span>
          </div>
        </div>

        <div 
          className="flex-1 p-2.5 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent cursor-pointer"
          onClick={handleSkipTyping}
        >
          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); option.action(); }}
                  disabled={option.disabled}
                  data-tutorial-id={option.dataTutorialId}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { materials } from '../../../../data/materials';
import { GAME_CONFIG } from '../../../../config/game-config';
import { InventoryItem } from '../../../../types/inventory';

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useShop = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, tutorialStep, inventory, unlockedRecipes } = state;

    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [saleCompleted, setSaleCompleted] = useState(false);
    const [lastSoldQuality, setLastSoldQuality] = useState<number>(100);
    const [refusalReaction, setRefusalReaction] = useState<'POLITE' | 'ANGRY' | null>(null);
    const [showInstanceSelector, setShowInstanceSelector] = useState(false);
    const [selectedInstance, setSelectedInstance] = useState<InventoryItem | null>(null);

    useEffect(() => {
        if (!activeCustomer) {
            setSaleCompleted(false);
            setRefusalReaction(null);
            setShowInstanceSelector(false);
            setSelectedInstance(null);
        }
    }, [activeCustomer]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const getItemName = useCallback((id: string) => {
        const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
        if (eq) return eq.name;
        const res = Object.values(materials).find(i => i.id === id);
        return res ? res.name : id;
    }, []);

    const matchingItems = useMemo(() => {
        if (!activeCustomer) return [];
        const { request } = activeCustomer;
        if (request.type === 'RESOURCE') {
            return inventory.filter(i => i.id === request.requestedId);
        } else {
            return inventory.filter(i => i.id.startsWith(request.requestedId));
        }
    }, [activeCustomer, inventory]);

    const executeSell = useCallback((item: InventoryItem) => {
        if (!activeCustomer || !item) return;
        if (item.isLocked) {
            actions.showToast("Item is locked and cannot be sold.");
            return;
        }
        const { mercenary, request } = activeCustomer;
        const isPipTutorial = tutorialStep === 'SELL_ITEM_GUIDE' && mercenary.id === 'pip_green';

        const itemQuality = item.equipmentData?.quality || 100;
        setLastSoldQuality(itemQuality);

        let affinityGain = isPipTutorial ? 10 : 2;
        if (itemQuality > 100) affinityGain += 2;
        else if (itemQuality < 80) affinityGain = Math.max(1, affinityGain - 1);

        const markup = request.markup || 1.25;
        const finalPrice = Math.ceil(item.baseValue * markup);

        if (item.type === 'RESOURCE') {
            actions.sellItem(item.id, 1, finalPrice, undefined, mercenary);
        } else {
            actions.sellItem(item.id, 1, finalPrice, item.id, mercenary);
        }

        spawnHearts(affinityGain);
        setSaleCompleted(true);
        setShowInstanceSelector(false);
        setSelectedInstance(null);
    }, [activeCustomer, tutorialStep, actions, spawnHearts]);

    const handleSellClick = useCallback(() => {
        if (!activeCustomer) return;
        if (matchingItems.length > 1) {
            setShowInstanceSelector(true);
        } else if (matchingItems.length === 1) {
            executeSell(matchingItems[0]);
        }
    }, [activeCustomer, matchingItems, executeSell]);

    const handleRefuse = useCallback(() => {
        if (!activeCustomer) return;
        const { mercenary } = activeCustomer;
        const affinity = mercenary.affinity || 0;
        const politeChance = affinity > 40 ? 0.8 : 0.3;
        const isPolite = Math.random() < politeChance;
        if (isPolite) {
            setRefusalReaction('POLITE');
            actions.refuseCustomer(mercenary.id, 0);
        } else {
            setRefusalReaction('ANGRY');
            actions.refuseCustomer(mercenary.id, 5);
        }
    }, [activeCustomer, actions]);

    const handleFarewell = useCallback(() => {
        setSaleCompleted(false);
        setRefusalReaction(null);
        actions.dismissCustomer();
    }, [actions]);

    const handleToggleShop = useCallback(() => {
        if (!isShopOpen && state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE') {
            actions.setTutorialStep('SELL_ITEM_GUIDE');
        }
        actions.toggleShop();
    }, [isShopOpen, state.tutorialStep, actions]);

    // --- Dialogue Generation ---
    const getThanksDialogue = useCallback(() => {
        const itemName = getItemName(activeCustomer?.request.requestedId || "");
        if (lastSoldQuality > 100) {
            return [
                `"Unbelievable! This ${itemName} is a true masterpiece. The edge is unlike anything I've seen. You really have the Lockhart touch!"`,
                `"Absolute perfection. I can feel the strength in this steel. I'll tell everyone in the tavern about your forge!"`,
                `"This quality is beyond what I expected. A fair price for legendary work. Thank you, Lockhart!"`
            ][Math.floor(Math.random() * 3)];
        } 
        if (lastSoldQuality < 80) {
            return [
                `"It'll do for now, I suppose. Though the finish on this ${itemName} is a bit rough... I hope your next work is a bit more refined."`,
                `"Hmm, not your best work, smith. I'll take it, but I was expecting that famous Lockhart quality. Try harder next time."`,
                `"A bit crude, but I need a blade today. Next time, I hope the anvil's rhythm is more precise."`
            ][Math.floor(Math.random() * 3)];
        }
        return [
            `"Fantastic craftsmanship! This ${itemName} is exactly what I needed. Thank you, Lockhart!"`,
            `"Superb work. I feel much safer with this by my side. I'll be back!"`,
            `"A fair price for quality steel. May your bellows never tire, smith."`,
            `"You truly have the Lockhart touch. This will serve me well in the ruins."`
        ][Math.floor(Math.random() * 4)];
    }, [activeCustomer, lastSoldQuality, getItemName]);

    const getRefusalDialogue = useCallback(() => {
        if (refusalReaction === 'POLITE') {
            return [
                `"I see. Perhaps another time then. Safe forging, smith."`,
                `"Ah, a shame. I'll keep looking elsewhere for now."`,
                `"Understandable. A Lockhart's work shouldn't be rushed. Farewell."`,
                `"I'll come back when your anvil is hotter. Until next time."`
            ][(activeCustomer?.id.length || 0) % 4];
        } else {
            return [
                `"What? I walked all this way for nothing? Hmph. Don't expect me back soon."`,
                `"A cold welcome for a paying customer... I'll find a better forge."`,
                `"Unbelievable. My old blade has more edge than your business sense!"`,
                `"I thought the Lockharts were more reliable. Guess I was wrong."`
            ][(activeCustomer?.id.length || 0) % 4];
        }
    }, [refusalReaction, activeCustomer]);

    const tutorialContent = useMemo(() => {
        if (tutorialStep === 'PIP_PRAISE_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "This... this is incredible. I can feel the balance in the grip. It's much better than the scraps I found in the woods. You really are a Lockhart, aren't you?",
                options: [{ label: "Continue", action: () => actions.setTutorialStep('DRAGON_TALK_DIALOG'), variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'DRAGON_TALK_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "The village... it hasn't been the same since the Dragon's fire. I lost my brother that night. I see that same shadow in your eyes, smith. We all lost someone. Good luck with the forge.",
                options: [{ label: "Farewell", action: () => { handleFarewell(); actions.setTutorialStep('TUTORIAL_END_DIALOG'); }, variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'TUTORIAL_END_DIALOG') {
            return {
                speaker: "Lockhart",
                text: "Finally... the first sale. It's just a simple bronze blade, but it marks the beginning of my resurgence. I will rebuild this forge, piece by piece, until the name Lockhart once again commands respect across the realm. Every strike of my hammer brings me closer to the day I face that dragon. ... I miss my people. I miss my home. But I will not falter. My business starts now.",
                options: [{ label: "The Shop is Open", action: () => actions.completeTutorial(), variant: 'primary' as const }]
            };
        }
        return null;
    }, [tutorialStep, activeCustomer, actions, handleFarewell]);

    const itemDetails = useMemo(() => {
        if (!activeCustomer) return undefined;
        const requestedId = activeCustomer.request.requestedId;
        const eq = EQUIPMENT_ITEMS.find(e => e.id === requestedId);
        const isUnlocked = eq ? (eq.unlockedByDefault !== false || unlockedRecipes.includes(requestedId)) : true;

        return {
            icon: eq?.icon || '📦',
            imageUrl: eq?.image ? getAssetUrl(eq.image) : getAssetUrl(`${requestedId}.png`),
            price: activeCustomer.request.price,
            requirements: eq?.requirements,
            isUnlocked
        };
        function getAssetUrl(filename: string) {
            return `https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/${filename}`;
        }
    }, [activeCustomer, unlockedRecipes]);

    const dialogueState = useMemo(() => {
        if (!isShopOpen) return null;
        if (tutorialContent) return tutorialContent;
        if (!activeCustomer) return null;

        if (saleCompleted) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getThanksDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'primary' as const }]
            };
        }

        if (refusalReaction) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getRefusalDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: (refusalReaction === 'ANGRY' ? 'danger' : 'neutral') as any }]
            };
        }

        return {
            speaker: activeCustomer.mercenary.name,
            text: activeCustomer.request.dialogue,
            highlightTerm: getItemName(activeCustomer.request.requestedId),
            itemDetail: itemDetails,
            options: [
                { 
                    label: `Sell`, 
                    action: handleSellClick, 
                    variant: 'primary' as const, 
                    disabled: !matchingItems.some(i => !i.isLocked),
                    dataTutorialId: tutorialStep === 'SELL_ITEM_GUIDE' ? 'SELL_BUTTON' : undefined
                },
                { 
                    label: "Refuse", 
                    action: handleRefuse, 
                    variant: 'danger' as const, 
                    disabled: tutorialStep === 'SELL_ITEM_GUIDE' 
                }
            ]
        };
    }, [
        isShopOpen, activeCustomer, tutorialContent, saleCompleted, refusalReaction, 
        getThanksDialogue, getRefusalDialogue, handleFarewell, handleSellClick, 
        handleRefuse, getItemName, itemDetails, matchingItems, tutorialStep
    ]);

    const canAffordOpen = state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP;
    const isTutorialActive = tutorialStep === 'SELL_ITEM_GUIDE' || !!tutorialContent;

    return {
        isShopOpen,
        activeCustomer,
        shopQueue,
        floatingHearts,
        dialogueState,
        showInstanceSelector,
        selectedInstance,
        matchingItems,
        canAffordOpen,
        isTutorialActive,
        refusalReaction,
        handlers: {
            handleToggleShop,
            handleFarewell,
            handleRefuse,
            handleSellClick,
            executeSell,
            setShowInstanceSelector,
            setSelectedInstance
        }
    };
};

